/** {@inheritDoc} */
public double solve(final UnivariateRealFunction f, double min, double max, double initial)
    throws MaxIterationsExceededException, FunctionEvaluationException {

    clearResult();
    verifyInterval(min, max);
    if ((initial < min) || (initial > max)) {
        throw MathRuntimeException.createIllegalArgumentException(
              "invalid interval, initial value parameters:  lower={0}, initial={1}, upper={2}",
              min, initial, max);
    }

    // Evaluate function at initial guess
    double yInitial = f.value(initial);
    if (Math.abs(yInitial) <= functionValueAccuracy) {
        // Initial guess is already a root within accuracy
        setResult(initial, 0);
        return initial;
    }

    // Evaluate function at endpoints
    double yMin = f.value(min);
    double yMax = f.value(max);

    // Check if initial guess and lower bound bracket the root
    if (yInitial * yMin < 0) {
        return solve(f, min, initial);
    }

    // Check if initial guess and upper bound bracket the root
    if (yInitial * yMax < 0) {
        return solve(f, initial, max);
    }

    // If initial doesn't help bracket, use original interval
    // Verify that the original interval brackets a root
    if (yMin * yMax >= 0) {
        throw MathRuntimeException.createIllegalArgumentException(
              "function values at endpoints do not have different signs.  " +
              "Endpoints: [{0}, {1}], Values: [{2}, {3}]",
              min, max, yMin, yMax);
    }

    // Fall back to standard bisection on the original interval
    return solve(f, min, max);
}

